Proposal as below, feel free to share your comments please. Thank you very much! @dzhulgakov @yuanbyu @ezyang @bddppq @ebarsoum @gramalingam 

You may refer to the whole proto file https://github.com/linkerzhang/onnx/blob/kezhan/add_function_to_onnx/onnx/onnx.in.proto.

```
// A named attribute containing either singular float, integer, string
// and tensor values, or repeated float, integer, string and tensor values.
// An AttributeProto MUST contain the name field, and *only one* of the
// following content fields, effectively enforcing a C/C++ union equivalent.
message AttributeProto {

  // Note: this enum is structurally identical to the OpSchema::AttrType
  // enum defined in schema.h.  If you rev one, you likely need to rev the other.
  enum AttributeType {
    UNDEFINED = 0;
    FLOAT = 1;
    INT = 2;
    STRING = 3;
    TENSOR = 4;
    GRAPH = 5;

    FLOATS = 6;
    INTS = 7;
    STRINGS = 8;
    TENSORS = 9;
    GRAPHS = 10;
  }

  // The name field MUST be present for this version of the IR.
  optional string name = 1;           // namespace Attribute
  optional bool is_ref = 21;          // if it's true, it means it's referring parent node's (referring to a function) attribute value.
  optional string ref_attr_name = 22; // if is_ref is true, ref_attr_name is the attribute name in parent function.

  // A human-readable documentation for this attribute. Markdown is allowed.
  optional string doc_string = 13;

  // The type field MUST be present for this version of the IR.
  // For 0.0.1 versions of the IR, this field was not defined, and
  // implementations needed to use has_field hueristics to determine
  // which value field was in use.  For IR_VERSION 0.0.2 or later, this
  // field MUST be set and match the f|i|s|t|... field in use.  This
  // change was made to accomodate proto3 implementations.
  optional AttributeType type = 20;   // discriminator that indicates which field below is in use

  // Exactly ONE of the following fields must be present for this version of the IR
  optional float f = 2;               // float
  optional int64 i = 3;               // int
  optional bytes s = 4;               // UTF-8 string
  optional TensorProto t = 5;         // tensor value
  optional GraphProto g = 6;          // graph
  // Do not use field below, it's deprecated.
  // optional ValueProto v = 12;         // value - subsumes everything but graph

  repeated float floats = 7;          // list of floats
  repeated int64 ints = 8;            // list of ints
  repeated bytes strings = 9;         // list of UTF-8 strings
  repeated TensorProto tensors = 10;  // list of tensors
  repeated GraphProto graphs = 11;    // list of graph
}

// Defines a function parameter.
message ParameterDeclProto {
  // The name of this parameter. Must be present.
  optional string name = 1;

  // The type/shape of this parameter.
  optional TypeProto type = 2; 

  // A human-readable doc string for this parameter. 
  optional string doc_string = 3; 
} 

// Defines a function attribute declaration.
message FuncAttrDeclProto {
  // The attribute name of the function. Must be present.
  optional string name = 1;

  // The type of this attribute.
  optional AttributeProto.AttributeType type = 2;
} 

// Defines a custom implementation of a function. 
message FunctionImplProto { 
  // The domain of this function implementation.
  optional string function_impl_domain = 1; 

  // The version of this implementation.
  optional int64 function_impl_version = 2; 

  // The URI of the executable. A runtime uses <domain> and <version> to
  // determine whether Compilation data itself saved in a separate file. 
  optional string executable_uri = 3;

  // The actual executable for this function implementation.
  optional bytes executable = 4;
} 
 
// Defines a function.
// We specify a function as a subgraph composed of ONNX ops. Any runtime can
// have a custom implementation optimized for the runtime. A runtime can use
// a matching custom implementation if there is one, or falls back to execute
// the subgraph.
// NOTE: We don't support recursive function.
message FunctionDefProto { 
  // The name of the function. MUST be present for this version of the IR. 
  optional string name = 1;
  
  // The domain of the function.
  optional string domain = 2;

  // The version of the function.
  optional int64 version = 3;

  // The input parameters of the function. 
  repeated ParameterDeclProto input_params = 4; 

  // The output parameters of the function. 
  repeated ParameterDeclProto output_params = 5;

  // The body of the function. 
  repeated NodeProto node = 6;

  // The function attributes' declaration.
  repeated FuncAttrDeclProto attr = 7;

  // An optional human-readable documentation for this function in the graph. 
  // MAY contain Markdown markup that conforms to http://commonmark.org/. 
  optional string doc_string = 8;

  // Custom implementations of this function. This enables runtime specific
  // implementations.
  repeated FunctionImplProto impl = 9;
 
  reserved 100 to 200; // for future extensions. 
}
```

